{
  "title": "स्केलिंग व्यवहार",
  "group": "ऑरोरा सर्वरलेस",
  "options": [
    {
      "text": "स्केलिंग की गति वर्तमान और कॉन्फ़िगर की गई क्षमता पर निर्भर करती है"
    },
    {
      "text": "डिमांड पर तुरंत स्केल होता है"
    },
    {
      "text": "केवल पूर्व-निर्धारित अंतराल पर ही स्केल होता है"
    },
    {
      "text": "केवल मैन्युअल स्केलिंग"
    }
  ],
  "questionProse": [
    "अचानक ट्रैफ़िक स्पाइक्स को हैंडल करने के लिए Aurora Serverless पर भरोसा करते समय सबसे महत्वपूर्ण बात क्या है?"
  ],
  "explanationProse": [
    "Aurora Serverless स्केलिंग:\n- Aurora Serverless v2 अपनी क्षमता को बारीक ACU इंक्रीमेंट्स में स्केल करता है\n- स्केलिंग की गति वर्तमान क्षमता और min/max ACU सेटिंग्स पर निर्भर करती है (इसलिए यह तुरंत नहीं होती)\n- सपोर्टेड वर्ज़न कॉन्फ़िगर किए जाने पर 0 ACUs पर ऑटो-पॉज़ हो सकते हैं\n- ACUs के आधार पर प्रति-सेकंड बिलिंग\n\nबेस्ट प्रैक्टिसेज़:\n- क्रिटिकल वर्कलोड्स पर अचानक स्पाइक्स के लिए मिनिमम कैपेसिटी को पर्याप्त ऊँचा रखें (ताकि स्केलिंग लेग से परफॉर्मेंस प्रभावित न हो)\n- स्केलिंग इवेंट्स को मॉनिटर करें\n- कनेक्शन मैनेजमेंट को ध्यान में रखें"
  ]
}
